import random

class RandomizedSet:
    def __init__(self) -> None:
        self._values: list[int] = []
        self._index: dict[int, int] = {}

    def insert(self, val: int) -> bool:
        if val in self._index:
            return False
        self._index[val] = len(self._values)
        self._values.append(val)
        return True

    def remove(self, val: int) -> bool:
        if val not in self._index:
            return False
        idx, last = self._index[val], self._values[-1]
        self._values[idx] = last
        self._index[last] = idx
        self._values.pop()
        del self._index[val]
        return True

    def getRandom(self) -> int:
        return random.choice(self._values)

import random

class RandomizedCollection:
    def __init__(self) -> None:
        self._values: list[int] = []
        self._indices: dict[int, set[int]] = {}

    def insert(self, val: int) -> bool:
        existed = val in self._indices and bool(self._indices[val])
        self._indices.setdefault(val, set()).add(len(self._values))
        self._values.append(val)
        return not existed

    def remove(self, val: int) -> bool:
        if val not in self._indices or not self._indices[val]:
            return False
        idx = next(iter(self._indices[val]))
        last = self._values[-1]
        self._values[idx] = last
        self._indices[val].discard(idx)
        self._indices[last].add(idx)
        self._indices[last].discard(len(self._values) - 1)
        self._values.pop()
        return True

    def getRandom(self) -> int:
        return random.choice(self._values)

from collections import deque

class PhoneDirectory:
    def __init__(self, max_numbers: int) -> None:
        self._available: deque[int] = deque(range(max_numbers))
        self._free: set[int] = set(range(max_numbers))

    def get(self) -> int:
        if not self._available:
            return -1
        n = self._available.popleft()
        self._free.discard(n)
        return n

    def check(self, number: int) -> bool:
        return number in self._free

    def release(self, number: int) -> None:
        if number not in self._free:
            self._free.add(number)
            self._available.append(number)

import heapq

class SeatManager:
    def __init__(self, n: int) -> None:
        self._free: list[int] = list(range(1, n + 1))
        heapq.heapify(self._free)

    def reserve(self) -> int:
        return heapq.heappop(self._free)

    def unreserve(self, seat_number: int) -> None:
        heapq.heappush(self._free, seat_number)

