class LRUCache:
    def __init__(self, capacity: int) -> None:
        self._capacity: int = capacity
        self._cache: OrderedDict[int, int] = OrderedDict()

    def get(self, key: int) -> int:
        if key not in self._cache:
            return -1
        self._cache.move_to_end(key)
        return self._cache[key]

    def put(self, key: int, value: int) -> None:
        if key in self._cache:
            self._cache.move_to_end(key)
        self._cache[key] = value
        if len(self._cache) > self._capacity:
            self._cache.popitem(last=False)

from collections import OrderedDict, defaultdict

class LFUCache:
    def __init__(self, capacity: int) -> None:
        self._capacity: int = capacity
        self._values: dict[int, tuple[int, int]] = {}
        self._buckets: defaultdict[int, OrderedDict[int, None]] = defaultdict(OrderedDict)
        self._min_freq: int = 0

    def _bump(self, key: int) -> None:
        value, freq = self._values[key]
        del self._buckets[freq][key]
        if not self._buckets[freq] and freq == self._min_freq:
            self._min_freq += 1
        self._buckets[freq + 1][key] = None
        self._values[key] = (value, freq + 1)

    def get(self, key: int) -> int:
        if key not in self._values:
            return -1
        self._bump(key)
        return self._values[key][0]

    def put(self, key: int, value: int) -> None:
        if self._capacity <= 0:
            return
        if key in self._values:
            self._values[key] = (value, self._values[key][1])
            self._bump(key)
            return
        if len(self._values) >= self._capacity:
            evict, _ = self._buckets[self._min_freq].popitem(last=False)
            del self._values[evict]
        self._values[key] = (value, 1)
        self._buckets[1][key] = None
        self._min_freq = 1

from collections import OrderedDict

class AuthenticationManager:
    def __init__(self, time_to_live: int) -> None:
        self._ttl: int = time_to_live
        self._tokens: OrderedDict[str, int] = OrderedDict()

    def _evict(self, current_time: int) -> None:
        while self._tokens:
            token, expiry = next(iter(self._tokens.items()))
            if expiry > current_time:
                break
            self._tokens.popitem(last=False)

    def generate(self, token_id: str, current_time: int) -> None:
        self._evict(current_time)
        self._tokens[token_id] = current_time + self._ttl

    def renew(self, token_id: str, current_time: int) -> None:
        self._evict(current_time)
        if token_id in self._tokens:
            del self._tokens[token_id]
            self._tokens[token_id] = current_time + self._ttl

    def countUnexpired(self, current_time: int) -> int:
        self._evict(current_time)
        return len(self._tokens)

class UndergroundSystem:
    def __init__(self) -> None:
        self._open: dict[int, tuple[str, int]] = {}
        self._totals: dict[tuple[str, str], tuple[int, int]] = {}

    def checkIn(self, id: int, station_name: str, t: int) -> None:
        self._open[id] = (station_name, t)

    def checkOut(self, id: int, station_name: str, t: int) -> None:
        start, t_in = self._open.pop(id)
        key = (start, station_name)
        total, count = self._totals.get(key, (0, 0))
        self._totals[key] = (total + (t - t_in), count + 1)

    def getAverageTime(self, start_station: str, end_station: str) -> float:
        total, count = self._totals[(start_station, end_station)]
        return total / count

