import string

class Codec:
    def __init__(self) -> None:
        self._long_to_short: dict[str, str] = {}
        self._short_to_long: dict[str, str] = {}
        self._alphabet: str = string.ascii_letters + string.digits

    def _generate(self) -> str:
        return ''.join(random.choices(self._alphabet, k=6))

    def encode(self, longUrl: str) -> str:
        if longUrl in self._long_to_short:
            return f'http://tinyurl.com/{self._long_to_short[longUrl]}'
        code = self._generate()
        while code in self._short_to_long:
            code = self._generate()
        self._long_to_short[longUrl] = code
        self._short_to_long[code] = longUrl
        return f'http://tinyurl.com/{code}'

    def decode(self, shortUrl: str) -> str:
        return self._short_to_long[shortUrl.rsplit('/', 1)[-1]]

from collections import deque

class HitCounter:
    def __init__(self) -> None:
        self._hits: deque[int] = deque()

    def hit(self, timestamp: int) -> None:
        self._hits.append(timestamp)

    def getHits(self, timestamp: int) -> int:
        while self._hits and self._hits[0] <= timestamp - 300:
            self._hits.popleft()
        return len(self._hits)

class Logger:
    def __init__(self) -> None:
        self._next_allowed: dict[str, int] = {}

    def shouldPrintMessage(self, timestamp: int, message: str) -> bool:
        if timestamp < self._next_allowed.get(message, 0):
            return False
        self._next_allowed[message] = timestamp + 10
        return True

import random
from typing import Optional

class ListNode:
    def __init__(self, val: int = 0, next: Optional['ListNode'] = None) -> None:
        self.val: int = val
        self.next: Optional['ListNode'] = next

class Solution:
    def __init__(self, head: Optional[ListNode]) -> None:
        self._head: Optional[ListNode] = head

    def getRandom(self) -> int:
        chosen: int = 0
        node: Optional[ListNode] = self._head
        i: int = 0
        while node is not None:
            if random.randint(0, i) == 0:
                chosen = node.val
            node = node.next
            i += 1
        return chosen

class _Bucket:
    def __init__(self, count: int = 0) -> None:
        self.count: int = count
        self.keys: set[str] = set()
        self.prev: '_Bucket | None' = None
        self.next: '_Bucket | None' = None

class AllOne:
    def __init__(self) -> None:
        self._head: _Bucket = _Bucket()
        self._tail: _Bucket = _Bucket()
        self._head.next = self._tail
        self._tail.prev = self._head
        self._of: dict[str, _Bucket] = {}

    def _insert_after(self, prev: _Bucket, count: int) -> _Bucket:
        node = _Bucket(count)
        node.prev = prev
        node.next = prev.next
        prev.next.prev = node
        prev.next = node
        return node

    def _detach(self, node: _Bucket) -> None:
        node.prev.next = node.next
        node.next.prev = node.prev

    def inc(self, key: str) -> None:
        cur = self._of.get(key, self._head)
        nxt = cur.next
        target_count = cur.count + 1
        if nxt is self._tail or nxt.count != target_count:
            nxt = self._insert_after(cur, target_count)
        nxt.keys.add(key)
        self._of[key] = nxt
        if cur is not self._head:
            cur.keys.discard(key)
            if not cur.keys:
                self._detach(cur)

    def dec(self, key: str) -> None:
        cur = self._of[key]
        if cur.count == 1:
            del self._of[key]
        else:
            prev = cur.prev
            target_count = cur.count - 1
            if prev is self._head or prev.count != target_count:
                prev = self._insert_after(prev, target_count)
            prev.keys.add(key)
            self._of[key] = prev
        cur.keys.discard(key)
        if not cur.keys:
            self._detach(cur)

    def getMaxKey(self) -> str:
        if self._tail.prev is self._head:
            return ''
        return next(iter(self._tail.prev.keys))

    def getMinKey(self) -> str:
        if self._head.next is self._tail:
            return ''
        return next(iter(self._head.next.keys))

