class Leaderboard:
    def __init__(self) -> None:
        self._scores: dict[int, int] = {}

    def addScore(self, playerId: int, score: int) -> None:
        self._scores[playerId] = self._scores.get(playerId, 0) + score

    def top(self, K: int) -> int:
        return sum(heapq.nlargest(K, self._scores.values()))

    def reset(self, playerId: int) -> None:
        self._scores.pop(playerId, None)

class MyCircularQueue:
    def __init__(self, k: int) -> None:
        self._buf: list[int] = [0] * k
        self._head: int = 0
        self._size: int = 0
        self._capacity: int = k

    def enQueue(self, value: int) -> bool:
        if self._size == self._capacity:
            return False
        self._buf[(self._head + self._size) % self._capacity] = value
        self._size += 1
        return True

    def deQueue(self) -> bool:
        if self._size == 0:
            return False
        self._head = (self._head + 1) % self._capacity
        self._size -= 1
        return True

    def Front(self) -> int:
        return -1 if self._size == 0 else self._buf[self._head]

    def Rear(self) -> int:
        return -1 if self._size == 0 else self._buf[(self._head + self._size - 1) % self._capacity]

    def isEmpty(self) -> bool:
        return self._size == 0

    def isFull(self) -> bool:
        return self._size == self._capacity
